int main(void){
    int a[65]={0},b[65]={0},x,y,t;
    cin>>x;
    for(int i=0;i<x;i++)cin>>t,a[t]=1;
	cin>>y;
	for(int i=0;i<y;i++)cin>>t,b[t]=1;
	cout<<x<<"\n";
    for(int i=0;i<65;i++){
    	if(a[i]&&b[i])cout<<i<<' ';
	}cout<<"\n";
	for(int i=0;i<65;i++){
    	if(a[i]||b[i])cout<<i<<' ';
	}
    
    return false;
}
